mapper.select:
select q.*,
       c.name as categoryName
from `question` q
left join `question_category` c on q.category_id = c.id

     and q.content like concat('%', #{content}, '%')
     and q.type = #{type}
     and q.category_id = #{categoryId}
     and q.difficulty = #{difficulty}
     and q.status = #{status}

order by q.id desc
